import type { FoldStrategy } from '../types.js';

/**
 * Quorum: majority agreement (K of N).
 * At least `threshold` streams must produce results that `agree()`.
 */
export function quorum<T>(
  threshold: number,
  agree: (a: T, b: T) => boolean,
): FoldStrategy<T, T> {
  return { type: 'quorum', threshold, agree };
}
