import type {
  BuleMeasure,
  PipelineConfig,
  PipelineMetrics,
  Stream,
  StreamId,
  StreamState,
} from './types.js';
import { fork } from './fork.js';
import { Superposition } from './superposition.js';
import { ReynoldsTracker } from './reynolds.js';
import { BackpressureController } from './backpressure.js';
import { TurbulentMultiplexer } from './multiplexer.js';
import { resetStreamIdCounter } from './stream.js';

/**
 * Pipeline — the computation topology engine.
 *
 * Orchestrates fork/race/fold operations across a DAG of streams,
 * tracks fluidic state (Reynolds number, β₁), and manages backpressure.
 */
export class Pipeline {
  private config: {
    capacity: number;
    highWaterMark: number;
    turbulentMultiplexing: boolean;
    onIdleSlot: (idleCount: number) => Stream[] | void;
    intrinsicBeta1?: number;
  };
  private allStreams = new Map<StreamId, Stream<unknown>>();
  private reynolds: ReynoldsTracker;
  private backpressure: BackpressureController;
  private multiplexer: TurbulentMultiplexer;

  constructor(config?: PipelineConfig) {
    this.config = {
      capacity: config?.capacity ?? 256,
      highWaterMark: config?.highWaterMark ?? 64,
      turbulentMultiplexing: config?.turbulentMultiplexing ?? false,
      onIdleSlot: config?.onIdleSlot ?? (() => undefined),
      intrinsicBeta1: config?.intrinsicBeta1,
    };

    this.reynolds = new ReynoldsTracker(
      this.config.capacity,
      this.config.intrinsicBeta1,
    );
    this.backpressure = new BackpressureController(this.config.highWaterMark);
    this.multiplexer = new TurbulentMultiplexer(
      this.reynolds,
      this.config.turbulentMultiplexing ? this.config.onIdleSlot : undefined,
    );

    // Reset stream ID counter for clean pipeline isolation
    resetStreamIdCounter();
  }

  /**
   * Static factory: create a Superposition from work functions.
   * This is the primary entry point for the fluent API.
   *
   * Usage:
   *   Pipeline.from([
   *     () => fetchFromVenueA(order),
   *     () => fetchFromVenueB(order),
   *     () => fetchFromVenueC(order),
   *   ]).race()
   */
  static from<T>(workFns: (() => Promise<T>)[]): Superposition<T> {
    const pipeline = new Pipeline();
    return pipeline.fork(workFns);
  }

  /**
   * Fork: create N parallel streams from work functions.
   * β₁ increases by (N - 1).
   */
  fork<T>(workFns: (() => Promise<T>)[]): Superposition<T> {
    const streams = fork(workFns);

    // Register parent-child relationships
    for (const stream of streams) {
      this.allStreams.set(stream.id, stream as Stream<unknown>);
      this.reynolds.updateStream(stream.id, stream.state);
    }

    return new Superposition<T>(streams, this.allStreams, this.reynolds);
  }

  /**
   * Get current pipeline metrics — fluidic state snapshot.
   */
  metrics(): PipelineMetrics {
    return this.reynolds.metrics();
  }

  /**
   * Signed Bule waste/opportunity measure for current runtime topology.
   * Available when intrinsicBeta1 is configured.
   */
  bule(): BuleMeasure | undefined {
    return this.reynolds.buleMeasure;
  }

  /**
   * Measure: observe all stream states without folding.
   */
  measure(): Map<StreamId, StreamState> {
    const result = new Map<StreamId, StreamState>();
    for (const [id, stream] of this.allStreams) {
      result.set(id, stream.state);
    }
    return result;
  }

  /**
   * Get the backpressure controller for advanced usage.
   */
  getBackpressure(): BackpressureController {
    return this.backpressure;
  }

  /**
   * Get the multiplexer for turbulent flow management.
   */
  getMultiplexer(): TurbulentMultiplexer {
    return this.multiplexer;
  }
}
