import type { StreamId } from './types.js';

/**
 * Interference: constructive (consensus) and destructive (conflict detection).
 *
 * Optimized with equivalence class grouping: O(N × G) where G = number of
 * distinct groups, instead of O(N²) pairwise comparison.
 * For data with many duplicates (common in quorum/consensus scenarios),
 * G << N so this is dramatically faster.
 * Falls back to O(N²) only when all values are unique (G ≈ N).
 */
export function interfere<T>(
  results: Map<StreamId, T>,
  mode: 'constructive' | 'destructive',
  compare: (a: T, b: T) => boolean,
): Map<StreamId, T> {
  const len = results.size;

  // Fast paths
  if (len <= 1) {
    return mode === 'constructive' ? new Map(results) : new Map();
  }

  const keys: StreamId[] = new Array(len);
  const vals: T[] = new Array(len);
  let idx = 0;
  for (const [k, v] of results) {
    keys[idx] = k;
    vals[idx] = v;
    idx++;
  }

  const threshold = (len - 1) / 2;

  // Group elements by equivalence class under the compare function.
  // groupRep[g] = index of the representative element for group g
  // groupMembers[g] = array of indices belonging to group g
  const groupRep: number[] = [];
  const groupMembers: number[][] = [];

  for (let i = 0; i < len; i++) {
    let assigned = false;
    for (let g = 0; g < groupRep.length; g++) {
      if (compare(vals[i], vals[groupRep[g]])) {
        groupMembers[g].push(i);
        assigned = true;
        break;
      }
    }
    if (!assigned) {
      groupRep.push(i);
      groupMembers.push([i]);
    }
  }

  // Each element's agreement count = (group size - 1)
  // This replaces the O(N²/2) pairwise loop with O(N) assignment
  const filtered = new Map<StreamId, T>();
  const isConstructive = mode === 'constructive';

  for (let g = 0; g < groupMembers.length; g++) {
    const members = groupMembers[g];
    const agreeCount = members.length - 1;
    const above = agreeCount > threshold;

    if (isConstructive ? above : !above) {
      for (let m = 0; m < members.length; m++) {
        const i = members[m];
        filtered.set(keys[i], vals[i]);
      }
    }
  }

  return filtered;
}
