import type { FoldStrategy, StreamId } from '../types.js';

export { winnerTakeAll } from './winner-take-all.js';
export { quorum } from './quorum.js';
export { mergeAll } from './merge-all.js';
export { consensus } from './consensus.js';
export { weighted } from './weighted.js';

/**
 * Apply a fold strategy to collected results.
 */
export function applyStrategy<T, R>(
  results: Map<StreamId, T>,
  vented: Set<StreamId>,
  strategy: FoldStrategy<T, R>,
): R {
  switch (strategy.type) {
    case 'winner-take-all': {
      if (strategy.selector) {
        return strategy.selector(results) as unknown as R;
      }
      // Default: first result (by stream ID order)
      const first = results.values().next();
      if (first.done) throw new Error('No results for winner-take-all');
      return first.value as unknown as R;
    }

    case 'quorum': {
      const values = Array.from(results.values());
      const len = values.length;
      const thresh = strategy.threshold;
      // Count agreements — early exit when quorum is met
      let bestValue = values[0];
      let bestCount = 0;
      for (let i = 0; i < len; i++) {
        let count = 0;
        for (let j = 0; j < len; j++) {
          if (strategy.agree(values[i], values[j])) count++;
        }
        if (count > bestCount) {
          bestCount = count;
          bestValue = values[i];
          // Early exit: if quorum met with max possible, stop
          if (bestCount === len) break;
        }
      }
      if (bestCount < thresh) {
        throw new Error(
          `Quorum not met: ${bestCount}/${thresh} agreements`,
        );
      }
      return bestValue as unknown as R;
    }

    case 'merge-all':
      return strategy.merge(results);

    case 'consensus': {
      const values = Array.from(results.values());
      const len = values.length;
      const halfLen = len / 2;
      if (strategy.mode === 'constructive') {
        // Find first value that agrees with majority — early return
        for (let i = 0; i < len; i++) {
          let agreeCount = 0;
          for (let j = 0; j < len; j++) {
            if (strategy.compare(values[i], values[j])) agreeCount++;
          }
          if (agreeCount > halfLen) {
            return values[i] as unknown as R;
          }
        }
        throw new Error('No constructive consensus reached');
      } else {
        // Destructive: find first outlier — early return
        for (let i = 0; i < len; i++) {
          let agreeCount = 0;
          for (let j = 0; j < len; j++) {
            if (strategy.compare(values[i], values[j])) agreeCount++;
          }
          if (agreeCount <= halfLen) {
            return values[i] as unknown as R;
          }
        }
        throw new Error('No outliers found — destructive interference found full consensus');
      }
    }

    case 'weighted': {
      const pairs: [T, number][] = [];
      for (const [streamId, value] of results) {
        const weight = strategy.weights.get(streamId) ?? 1;
        pairs.push([value, weight]);
      }
      return strategy.merge(pairs);
    }

    case 'custom':
      return strategy.fold(results, vented);

    default:
      throw new Error(`Unknown fold strategy: ${(strategy as { type: string }).type}`);
  }
}
