import type { FoldStrategy, StreamId } from '../types.js';

/**
 * Merge-all: all results contribute (Worthington Whip).
 * Every non-vented result is passed to the merger function.
 */
export function mergeAll<T, R>(
  merge: (results: Map<StreamId, T>) => R,
): FoldStrategy<T, R> {
  return { type: 'merge-all', merge };
}
