import type { FoldStrategy, Stream, StreamId } from './types.js';
import { executeStream } from './stream.js';
import { applyStrategy } from './strategies/index.js';

/**
 * Fold: wait for all streams, merge results via strategy.
 * β₁ decreases — parallel paths converge to a single result.
 */
export async function fold<T, R = T>(
  streams: Stream<T>[],
  strategy: FoldStrategy<T, R>,
): Promise<R> {
  if (streams.length === 0) {
    throw new Error('fold() requires at least one stream');
  }

  // Execute all streams concurrently, collecting results
  const len = streams.length;
  const promises: Promise<T>[] = new Array(len);
  for (let i = 0; i < len; i++) {
    const s = streams[i];
    promises[i] = s.state === 'completed'
      ? Promise.resolve(s.result as T)
      : s.state === 'vented'
        ? Promise.reject(new Error(`Stream ${s.id} vented`))
        : executeStream(s);
  }
  const settled = await Promise.allSettled(promises);

  const results = new Map<StreamId, T>();
  const vented = new Set<StreamId>();

  for (let i = 0; i < streams.length; i++) {
    const outcome = settled[i];
    if (outcome.status === 'fulfilled') {
      results.set(streams[i].id, outcome.value);
    } else {
      vented.add(streams[i].id);
    }
  }

  if (results.size === 0) {
    throw new Error('All streams were vented — nothing to fold');
  }

  return applyStrategy(results, vented, strategy);
}
