import type { Stream, StreamId } from './types.js';
import { executeStream } from './stream.js';
import { ventStream } from './vent.js';

export interface RaceResult<T> {
  winner: StreamId;
  result: T;
}

/**
 * Race: first to complete wins, losers are vented via AbortSignal.
 * This is waveform fold — superposition resolves to a single state.
 */
export async function race<T>(
  streams: Stream<T>[],
  allStreams?: Map<StreamId, Stream<unknown>>,
): Promise<RaceResult<T>> {
  if (streams.length === 0) {
    throw new Error('race() requires at least one stream');
  }

  if (streams.length === 1) {
    const result = await executeStream(streams[0]);
    return { winner: streams[0].id, result };
  }

  return new Promise<RaceResult<T>>((resolve, reject) => {
    let settled = false;
    let errorCount = 0;

    for (const stream of streams) {
      executeStream(stream).then(
        (result) => {
          if (settled) return;
          settled = true;

          // Vent all losers
          for (const loser of streams) {
            if (loser.id !== stream.id && loser.state === 'active') {
              ventStream(loser, allStreams);
            }
          }

          resolve({ winner: stream.id, result });
        },
        () => {
          errorCount++;
          // Only reject if ALL streams failed
          if (errorCount === streams.length && !settled) {
            settled = true;
            reject(new Error('All streams in race failed'));
          }
        },
      );
    }
  });
}
