import type { Stream, StreamId } from './types.js';

// Terminal states that vent should skip — check by first char for speed
// 'v'ented, 'c'ompleted, 't'unneled
function isTerminal(state: string): boolean {
  const c = state.charCodeAt(0);
  // v=118, c=99, t=116
  return c === 118 || c === 99 || c === 116;
}

/**
 * Vent: propagate to descendants, NOT siblings.
 * Iterative DFS down the child tree — avoids stack frame overhead for deep trees.
 * Batch timestamp: single Date.now() for the entire vent wave.
 */
export function ventStream<T>(
  stream: Stream<T>,
  allStreams?: Map<StreamId, Stream<unknown>>,
): void {
  const ts = Date.now(); // Single timestamp for entire batch
  const stack: Stream<unknown>[] = [stream];

  while (stack.length > 0) {
    const current = stack.pop()!;

    if (isTerminal(current.state)) continue;

    current.state = 'vented';
    current.completedAt = ts;
    // Only abort if controller was allocated (lazy init)
    if (current.controller) current.controller.abort();

    // Push children onto stack (descendants only, never siblings)
    if (allStreams) {
      const children = current.childIds;
      for (let i = children.length - 1; i >= 0; i--) {
        const child = allStreams.get(children[i]);
        if (child) stack.push(child);
      }
    }
  }
}

/**
 * Evaluate a vent predicate against a stream's result.
 * Returns true if the stream should be vented.
 */
export function shouldVent<T>(
  result: T,
  stream: Stream<T>,
  predicate: (result: T, stream: Stream<T>) => boolean,
): boolean {
  return predicate(result, stream);
}
