import type { FoldStrategy, StreamId } from '../types.js';

/**
 * Winner-take-all: first/best result wins.
 * Race semantics applied as a fold strategy.
 */
export function winnerTakeAll<T>(
  selector?: (results: Map<StreamId, T>) => T,
): FoldStrategy<T, T> {
  return { type: 'winner-take-all', selector };
}
