import type { WorkFrame, StreamId } from './types.js';

// Reuse encoder/decoder — amortize allocation cost
const encoder = new TextEncoder();
const decoder = new TextDecoder();

// Reusable empty array for no-metadata case
const EMPTY_BYTES = new Uint8Array(0);

/**
 * Create a self-describing work frame.
 * Frames carry identity (stream_id + sequence) so they can be
 * reassembled out of order — like Okazaki fragments on the lagging strand.
 */
export function createFrame<T>(
  streamId: StreamId,
  sequence: number,
  payload: T,
  metadata?: Record<string, unknown>,
): WorkFrame<T> {
  return {
    streamId,
    sequence,
    payload,
    metadata,
    emittedAt: Date.now(),
  };
}

/**
 * Encode a WorkFrame to a minimal binary representation.
 * Header: streamId (u16) + sequence (u32) + timestamp (u48) = 12 bytes + 4 bytes meta length = 16 bytes
 * Payload follows as JSON-encoded bytes.
 */
export function encodeFrame<T>(frame: WorkFrame<T>): Uint8Array {
  const payloadBytes = encoder.encode(JSON.stringify(frame.payload));
  const metaBytes = frame.metadata
    ? encoder.encode(JSON.stringify(frame.metadata))
    : EMPTY_BYTES;

  const totalLen = 16 + payloadBytes.length + metaBytes.length;
  const buffer = new ArrayBuffer(totalLen);
  const view = new DataView(buffer);
  const bytes = new Uint8Array(buffer);

  view.setUint16(0, frame.streamId);
  view.setUint32(2, frame.sequence);
  // Timestamp as 6 bytes (48-bit, good until year 10889)
  const ts = frame.emittedAt;
  view.setUint16(6, (ts / 0x100000000) & 0xffff);
  view.setUint32(8, ts & 0xffffffff);
  view.setUint32(12, metaBytes.length);

  bytes.set(payloadBytes, 16);
  if (metaBytes.length > 0) bytes.set(metaBytes, 16 + payloadBytes.length);

  return bytes;
}

/**
 * Decode a binary-encoded WorkFrame.
 * Uses subarray instead of slice to avoid copies.
 */
export function decodeFrame<T>(bytes: Uint8Array): WorkFrame<T> {
  const view = new DataView(bytes.buffer, bytes.byteOffset, bytes.byteLength);

  const streamId = view.getUint16(0);
  const sequence = view.getUint32(2);
  const tsHigh = view.getUint16(6);
  const tsLow = view.getUint32(8);
  const emittedAt = tsHigh * 0x100000000 + tsLow;
  const metaLength = view.getUint32(12);

  const payloadEnd = bytes.length - metaLength;
  const payload = JSON.parse(decoder.decode(bytes.subarray(16, payloadEnd))) as T;

  let metadata: Record<string, unknown> | undefined;
  if (metaLength > 0) {
    metadata = JSON.parse(decoder.decode(bytes.subarray(payloadEnd)));
  }

  return { streamId, sequence, payload, metadata, emittedAt };
}
