import type { Stream, StreamId, StreamState } from './types.js';

let nextStreamId = 1;

// ─── Batch timestamp cache ─────────────────────────────────────────────────
// Amortizes Date.now() across batch operations (fork creates N streams,
// vent hits N descendants). Single call per batch instead of per-item.
let _batchTs = 0;

export function beginBatch(): void {
  _batchTs = Date.now();
}

export function endBatch(): void {
  _batchTs = 0;
}

function now(): number {
  return _batchTs || Date.now();
}

export function resetStreamIdCounter(): void {
  nextStreamId = 1;
}

// ─── Numeric state IDs for bitmask transitions ─────────────────────────────
const STATE_ID: Record<StreamState, number> = {
  pending: 0, superposed: 1, active: 2, completed: 3,
  vented: 4, tunneled: 5, entangled: 6,
};

// Bitmask per source state: bit N set = transition to state N is valid
// pending(0)     → superposed(1), active(2), vented(4)
// superposed(1)  → active(2), vented(4), tunneled(5), entangled(6)
// active(2)      → completed(3), vented(4), tunneled(5)
// completed(3)   → (none)
// vented(4)    → (none)
// tunneled(5)    → (none)
// entangled(6)   → active(2), completed(3), vented(4), tunneled(5)
const TRANSITION_MASK: Uint8Array = new Uint8Array([
  (1 << 1) | (1 << 2) | (1 << 4),               // 0: pending
  (1 << 2) | (1 << 4) | (1 << 5) | (1 << 6),    // 1: superposed
  (1 << 3) | (1 << 4) | (1 << 5),                // 2: active
  0,                                               // 3: completed
  0,                                               // 4: vented
  0,                                               // 5: tunneled
  (1 << 2) | (1 << 3) | (1 << 4) | (1 << 5),    // 6: entangled
]);

export function createStream<T>(
  work: () => Promise<T>,
  parentId: StreamId | null = null,
): Stream<T> {
  const id = nextStreamId++;
  return {
    id,
    parentId,
    childIds: [],
    state: 'pending',
    work,
    controller: null as unknown as AbortController, // Lazy — created when needed
    createdAt: now(),
  };
}

/**
 * Ensure a stream has an AbortController.
 * Deferred from createStream to avoid allocation for streams
 * that are never executed (e.g., fork benchmarks, measurement).
 */
export function ensureController<T>(stream: Stream<T>): AbortController {
  if (!stream.controller) {
    stream.controller = new AbortController();
  }
  return stream.controller;
}

export function transitionState<T>(
  stream: Stream<T>,
  to: StreamState,
): void {
  const toId = STATE_ID[to];
  if (!(TRANSITION_MASK[STATE_ID[stream.state]] & (1 << toId))) {
    throw new Error(
      `Invalid state transition: ${stream.state} → ${to} (stream ${stream.id})`,
    );
  }

  stream.state = to;

  if (toId === 2) { // active
    stream.startedAt = now();
  } else if (toId >= 3 && toId <= 5) { // completed, vented, tunneled
    stream.completedAt = now();
  }
}

export function executeStream<T>(stream: Stream<T>): Promise<T> {
  transitionState(stream, 'active');
  const controller = ensureController(stream);

  return new Promise<T>((resolve, reject) => {
    controller.signal.addEventListener('abort', () => {
      reject(new Error(`Stream ${stream.id} aborted`));
    });

    stream.work().then(
      (result) => {
        if (stream.state === 'vented') {
          reject(new Error(`Stream ${stream.id} was vented`));
          return;
        }
        stream.result = result;
        transitionState(stream, 'completed');
        resolve(result);
      },
      (error) => {
        if (stream.state !== 'vented') {
          stream.error = error instanceof Error ? error : new Error(String(error));
          try {
            transitionState(stream, 'vented');
          } catch {
            // Already in terminal state
          }
        }
        reject(error);
      },
    );
  });
}
