import type { WorkFrame, StreamId } from './types.js';

export interface ReassemblerConfig {
  maxBufferPerStream?: number;
  maxGap?: number;
}

/**
 * Per-stream out-of-order buffer.
 * Uses a sparse array indexed by (sequence - base) for O(1) access.
 * Array index access is pointer arithmetic; Map.get() has hash overhead.
 */
interface StreamBuffer<T> {
  base: number;           // The 'expected' value when buffer was created
  frames: (WorkFrame<T> | undefined)[];
  count: number;          // Number of frames in buffer
  maxSeq: number;         // Highest sequence seen (for drain optimization)
}

/**
 * Out-of-order frame reassembler.
 * Optimized with:
 * - Fast path for in-order delivery (no buffer allocation)
 * - Single-stream cache (avoids Map lookup on consecutive same-stream pushes)
 * - Array-based sparse buffer (O(1) access vs Map hash overhead)
 * - Reusable single-element return array (avoids per-push allocation)
 */
export class FrameReassembler<T = unknown> {
  private maxBuffer: number;
  private maxGap: number;
  private buffers = new Map<StreamId, StreamBuffer<T>>();
  private nextExpected = new Map<StreamId, number>();
  private _delivered = 0;
  private _buffered = 0;
  private _reordered = 0;

  // Single-stream cache — avoids Map lookup on repeated same-stream pushes
  private _lastStreamId: StreamId = -1;
  private _lastExpected = 0;

  constructor(config: ReassemblerConfig = {}) {
    this.maxBuffer = config.maxBufferPerStream ?? 256;
    this.maxGap = config.maxGap ?? 64;
  }

  // Reusable arrays to avoid allocation on hot paths
  private static readonly EMPTY: WorkFrame<never>[] = [];
  private _singleResult: WorkFrame<T>[] = [null as unknown as WorkFrame<T>];

  push(frame: WorkFrame<T>): WorkFrame<T>[] {
    const { streamId, sequence } = frame;

    // Fast cache hit for same stream as last push
    let expected: number;
    if (streamId === this._lastStreamId) {
      expected = this._lastExpected;
    } else {
      expected = this.nextExpected.get(streamId) ?? 0;
      this._lastStreamId = streamId;
    }

    // Fast path: in-order frame with no buffered frames
    if (sequence === expected) {
      this._delivered++;
      const buffer = this.buffers.get(streamId);

      if (!buffer || buffer.count === 0) {
        // No buffer — most common case. Skip buffer lookup entirely.
        const next = sequence + 1;
        this.nextExpected.set(streamId, next);
        this._lastExpected = next;
        this._singleResult[0] = frame;
        return this._singleResult;
      }

      // Has buffer — drain consecutive using array index access
      const deliverable: WorkFrame<T>[] = new Array(buffer.count + 1);
      deliverable[0] = frame;
      let count = 1;
      let next = sequence + 1;
      const frames = buffer.frames;
      const base = buffer.base;
      let idx = next - base;

      while (idx < frames.length && frames[idx] !== undefined) {
        deliverable[count++] = frames[idx]!;
        frames[idx] = undefined; // Clear slot
        buffer.count--;
        this._buffered--;
        this._delivered++;
        next++;
        idx++;
      }

      this.nextExpected.set(streamId, next);
      this._lastExpected = next;
      if (buffer.count === 0) this.buffers.delete(streamId);
      if (count < deliverable.length) deliverable.length = count;
      return deliverable;
    }

    // Duplicate or already-delivered
    if (sequence < expected) return FrameReassembler.EMPTY;

    // Out-of-order: buffer it
    const gap = sequence - expected;
    if (gap > this.maxGap) return FrameReassembler.EMPTY;

    let buffer = this.buffers.get(streamId);
    if (!buffer) {
      buffer = { base: expected, frames: new Array(this.maxGap + 1), count: 0, maxSeq: sequence };
      this.buffers.set(streamId, buffer);
    }

    if (buffer.count >= this.maxBuffer) return FrameReassembler.EMPTY;

    // Array index = sequence - base
    const arrIdx = sequence - buffer.base;
    if (arrIdx >= buffer.frames.length) {
      // Grow array if needed
      const newLen = arrIdx + 16;
      const newFrames = new Array(newLen);
      for (let i = 0; i < buffer.frames.length; i++) {
        newFrames[i] = buffer.frames[i];
      }
      buffer.frames = newFrames;
    }

    if (buffer.frames[arrIdx] === undefined) {
      buffer.frames[arrIdx] = frame;
      buffer.count++;
      this._buffered++;
      this._reordered++;
    }
    return FrameReassembler.EMPTY;
  }

  reset(streamId: StreamId): void {
    this.buffers.delete(streamId);
    this.nextExpected.delete(streamId);
    if (this._lastStreamId === streamId) {
      this._lastStreamId = -1;
      this._lastExpected = 0;
    }
  }

  get stats() {
    return {
      delivered: this._delivered,
      buffered: this._buffered,
      reordered: this._reordered,
      activeStreams: this.buffers.size,
    };
  }
}
