import type { Stream, StreamId, StreamState } from './types.js';

export interface MeasurementSnapshot<T> {
  state: StreamState;
  result?: T;
  startedAt?: number;
  completedAt?: number;
  childCount: number;
  entangledWith: StreamId[];
}

/**
 * Measurement: observe state without folding.
 * Unlike fold/race, measurement does NOT trigger execution or affect stream state.
 * Pure observation of the current quantum state.
 */
export function measure<T>(
  streams: Stream<T>[],
): Map<StreamId, MeasurementSnapshot<T>> {
  const snapshots = new Map<StreamId, MeasurementSnapshot<T>>();

  for (const stream of streams) {
    snapshots.set(stream.id, {
      state: stream.state,
      result: stream.result,
      startedAt: stream.startedAt,
      completedAt: stream.completedAt,
      childCount: stream.childIds.length,
      entangledWith: stream.entangledWith ?? [],
    });
  }

  return snapshots;
}
