import type { Stream, StreamId } from './types.js';
import { createStream, transitionState, beginBatch, endBatch } from './stream.js';

/**
 * Fork: parent → N children.
 * β₁ increases by (N - 1) — each new parallel path adds an independent cycle.
 * Uses batch timestamp — single Date.now() call for the entire fork.
 */
export function fork<T>(
  workFns: (() => Promise<T>)[],
  parentId: StreamId | null = null,
): Stream<T>[] {
  if (workFns.length === 0) {
    throw new Error('fork() requires at least one work function');
  }

  const len = workFns.length;
  const streams: Stream<T>[] = new Array(len);

  beginBatch();
  for (let i = 0; i < len; i++) {
    const stream = createStream(workFns[i], parentId);
    transitionState(stream, 'superposed');
    streams[i] = stream;
  }
  endBatch();

  return streams;
}

/**
 * Calculate β₁ change from a fork operation.
 * Forking into N children adds (N - 1) independent parallel paths.
 */
export function forkBettiDelta(childCount: number): number {
  return Math.max(0, childCount - 1);
}
