import type {
  FoldStrategy,
  VentPredicate,
  SearchConfig,
  Stream,
  StreamId,
  StreamState,
  TunnelPredicate,
} from './types.js';
import { executeStream, transitionState } from './stream.js';
import { race as raceStreams, type RaceResult } from './race.js';
import { fold as foldStreams } from './fold.js';
import { ventStream, shouldVent } from './vent.js';
import { tunnel } from './tunneling.js';
import { interfere } from './interference.js';
import { measure, type MeasurementSnapshot } from './measurement.js';
import { entangle, entangledWork } from './entanglement.js';
import { search, type SearchResult } from './search.js';
import { fork } from './fork.js';
import type { ReynoldsTracker } from './reynolds.js';

/**
 * Superposition — work exists in N parallel states simultaneously.
 * Chainable builder that composes fork/race/fold/vent operations.
 */
export class Superposition<T> {
  private streams: Stream<T>[];
  private allStreams: Map<StreamId, Stream<unknown>>;
  private ventPredicates: VentPredicate<T>[] = [];
  private tunnelPredicates: TunnelPredicate<T>[] = [];
  private interferenceConfig?: {
    mode: 'constructive' | 'destructive';
    compare: (a: T, b: T) => boolean;
  };
  private entangledState?: unknown;
  private reynolds?: ReynoldsTracker;

  constructor(
    streams: Stream<T>[],
    allStreams: Map<StreamId, Stream<unknown>>,
    reynolds?: ReynoldsTracker,
  ) {
    this.streams = streams;
    this.allStreams = allStreams;
    this.reynolds = reynolds;

    // Register in global stream map
    for (const s of streams) {
      this.allStreams.set(s.id, s as Stream<unknown>);
      this.reynolds?.updateStream(s.id, s.state);
    }
  }

  // ─── Core 4 ─────────────────────────────────────────────────────────────

  /**
   * Race: first to complete wins, losers vented.
   */
  async race(): Promise<RaceResult<T>> {
    const streams = this.prepareStreams();
    const result = await raceStreams(streams, this.allStreams);
    this.updateMetrics();
    return result;
  }

  /**
   * Fold: wait for all, merge via strategy.
   */
  async fold<R = T>(strategy: FoldStrategy<T, R>): Promise<R> {
    const streams = this.prepareStreams();
    const result = await foldStreams(streams, strategy);
    this.updateMetrics();
    return result;
  }

  /**
   * Vent: register a predicate that auto-vents streams on result.
   * Chainable — predicates accumulate.
   */
  vent(predicate: VentPredicate<T>): Superposition<T> {
    this.ventPredicates.push(predicate);
    return this;
  }

  // ─── Quantum modalities ─────────────────────────────────────────────────

  /**
   * Tunnel: early exit when confidence threshold met.
   */
  tunnel(predicate: TunnelPredicate<T>): Superposition<T> {
    this.tunnelPredicates.push(predicate);
    return this;
  }

  /**
   * Interfere: constructive (consensus) or destructive (conflict detection).
   */
  interfere(
    mode: 'constructive' | 'destructive',
    compare: (a: T, b: T) => boolean,
  ): Superposition<T> {
    this.interferenceConfig = { mode, compare };
    return this;
  }

  /**
   * Measure: observe state without folding.
   */
  async measure(): Promise<Map<StreamId, MeasurementSnapshot<T>>> {
    return measure(this.streams);
  }

  /**
   * Entangle: shared state across parallel streams.
   */
  entangle(sharedState: unknown): Superposition<T> {
    this.entangledState = sharedState;
    entangle(this.streams, sharedState);
    return this;
  }

  /**
   * Search: Grover-style amplification loop.
   */
  async search(config: SearchConfig<T>): Promise<SearchResult<T>> {
    // Execute all streams first to get initial candidates
    const streams = this.prepareStreams();
    const settled = await Promise.allSettled(
      streams.map((s) =>
        s.state === 'completed' ? Promise.resolve(s.result as T) : executeStream(s),
      ),
    );

    const candidates: T[] = [];
    for (const s of settled) {
      if (s.status === 'fulfilled') {
        candidates.push(s.value as T);
      }
    }

    if (candidates.length === 0) {
      throw new Error('No candidates for search — all streams failed');
    }

    return search(candidates, config);
  }

  // ─── Composition ────────────────────────────────────────────────────────

  /**
   * Chain: map results into new fork.
   */
  then<U>(fn: (result: T) => (() => Promise<U>)[]): Superposition<U> {
    // Create a deferred superposition that executes after this one folds
    const deferredStreams: Stream<U>[] = [];
    const allStreams = this.allStreams;
    const reynolds = this.reynolds;

    // We need a proxy that will resolve when this superposition completes
    const parentStreams = this.streams;

    // Create placeholder streams that will be replaced
    const placeholder = fork<U>(
      [() => Promise.resolve(undefined as unknown as U)],
      null,
    );

    // Return a new superposition that chains off this one
    const chained = new Superposition<U>(placeholder, allStreams, reynolds);

    // Override race/fold to first execute this superposition
    const originalRace = chained.race.bind(chained);
    const originalFold = chained.fold.bind(chained);

    chained.race = async () => {
      // Execute parent streams, get first result, fork into new work
      const { result } = await this.race();
      const newWorkFns = fn(result);
      const newStreams = fork<U>(newWorkFns);
      chained.streams = newStreams;
      for (const s of newStreams) allStreams.set(s.id, s as Stream<unknown>);
      return raceStreams(newStreams, allStreams);
    };

    chained.fold = async <R = U>(strategy: FoldStrategy<U, R>) => {
      const { result } = await this.race();
      const newWorkFns = fn(result);
      const newStreams = fork<U>(newWorkFns);
      chained.streams = newStreams;
      for (const s of newStreams) allStreams.set(s.id, s as Stream<unknown>);
      return foldStreams(newStreams, strategy);
    };

    return chained;
  }

  // ─── Internal ───────────────────────────────────────────────────────────

  /**
   * Prepare streams by wrapping work functions with vent/tunnel predicates.
   */
  private prepareStreams(): Stream<T>[] {
    for (const stream of this.streams) {
      if (this.ventPredicates.length > 0 || this.tunnelPredicates.length > 0) {
        const originalWork = stream.work;
        const ventPreds = this.ventPredicates;
        const tunnelPreds = this.tunnelPredicates;
        const allStreams = this.allStreams;

        stream.work = async () => {
          const result = await originalWork();

          // Check vent predicates
          for (const pred of ventPreds) {
            if (shouldVent(result, stream, pred)) {
              ventStream(stream, allStreams);
              throw new Error(`Stream ${stream.id} vented by predicate`);
            }
          }

          return result;
        };
      }
    }

    return this.streams;
  }

  private updateMetrics(): void {
    if (!this.reynolds) return;
    for (const stream of this.streams) {
      this.reynolds.updateStream(stream.id, stream.state);
    }
  }
}
