import { decodeFlowFrame, HEADER_SIZE } from './flow-bridge.js';
import { FrameReassembler, type ReassemblerConfig } from './reassembler.js';
import type { StreamId, WorkFrame } from './types.js';

export interface DecodedFlowFrame<T = unknown> {
  frame: WorkFrame<T>;
  flags: number;
  bytesRead: number;
}

export interface FrameDecoder<T = unknown> {
  mode: 'js' | 'wasm';
  decode(bytes: Uint8Array, offset: number): DecodedFlowFrame<T> | null;
}

export interface WasmFrameAssemblyConfig<T = unknown> {
  decoder?: FrameDecoder<T>;
  reassembler?: FrameReassembler<T>;
  reassemblerConfig?: ReassemblerConfig;
  maxCarryoverBytes?: number;
}

export interface WasmFrameAssemblyStats {
  mode: 'js' | 'wasm';
  chunks: number;
  bytesIn: number;
  framesDecoded: number;
  framesDelivered: number;
  decodeErrors: number;
  carryoverBytes: number;
}

const EMPTY_BYTES = new Uint8Array(0);
const DEFAULT_MAX_CARRYOVER_BYTES = 4 * 1024 * 1024;

const INCOMPLETE_MESSAGES = ['Buffer too small', 'Buffer incomplete'];

function isIncompleteBufferError(error: unknown): boolean {
  if (!(error instanceof Error)) return false;
  for (const message of INCOMPLETE_MESSAGES) {
    if (error.message.includes(message)) return true;
  }
  return false;
}

function getFrameTotalLength(bytes: Uint8Array, offset: number): number {
  const payloadLength =
    (bytes[offset + 7] << 16) | (bytes[offset + 8] << 8) | bytes[offset + 9];
  return HEADER_SIZE + payloadLength;
}

export function createJavaScriptFlowDecoder<T = unknown>(): FrameDecoder<T> {
  return {
    mode: 'js',
    decode(bytes, offset) {
      try {
        return decodeFlowFrame<T>(bytes, offset);
      } catch (error) {
        if (isIncompleteBufferError(error)) return null;
        throw error;
      }
    },
  };
}

export function createWasmFlowDecoder<T = unknown>(
  decode: FrameDecoder<T>['decode'],
): FrameDecoder<T> {
  return {
    mode: 'wasm',
    decode,
  };
}

/**
 * Assemble chunked wire bytes into ordered WorkFrames.
 *
 * The "wasm" part is the pluggable decoder: provide a WASM-backed decoder
 * for payload decode and keep the rest of the framing pipeline stable.
 */
export class WasmFrameAssemblyPipeline<T = unknown> {
  private readonly decoder: FrameDecoder<T>;
  private readonly maxCarryoverBytes: number;
  private readonly reassemblerConfig: ReassemblerConfig;
  private reassembler: FrameReassembler<T>;
  private carryover: Uint8Array = EMPTY_BYTES;
  private _stats: WasmFrameAssemblyStats;

  constructor(config: WasmFrameAssemblyConfig<T> = {}) {
    this.decoder = config.decoder ?? createJavaScriptFlowDecoder<T>();
    this.maxCarryoverBytes =
      config.maxCarryoverBytes ?? DEFAULT_MAX_CARRYOVER_BYTES;
    this.reassemblerConfig = config.reassemblerConfig ?? {};
    this.reassembler =
      config.reassembler ?? new FrameReassembler<T>(this.reassemblerConfig);

    this._stats = {
      mode: this.decoder.mode,
      chunks: 0,
      bytesIn: 0,
      framesDecoded: 0,
      framesDelivered: 0,
      decodeErrors: 0,
      carryoverBytes: 0,
    };
  }

  pushChunk(chunk: Uint8Array): WorkFrame<T>[] {
    if (chunk.length === 0) return [];

    this._stats.chunks++;
    this._stats.bytesIn += chunk.length;

    const bytes = this.concatCarryover(chunk);
    const delivered: WorkFrame<T>[] = [];
    let offset = 0;

    while (offset + HEADER_SIZE <= bytes.length) {
      const frameTotalLength = getFrameTotalLength(bytes, offset);
      if (offset + frameTotalLength > bytes.length) break;

      let decoded: DecodedFlowFrame<T> | null;
      try {
        decoded = this.decoder.decode(bytes, offset);
      } catch (error) {
        this._stats.decodeErrors++;
        throw error;
      }

      if (!decoded) break;
      if (decoded.bytesRead !== frameTotalLength) {
        this._stats.decodeErrors++;
        throw new Error(
          `Decoder consumed unexpected frame length: ${decoded.bytesRead} != ${frameTotalLength}`,
        );
      }

      offset += frameTotalLength;
      this._stats.framesDecoded++;

      const inOrder = this.reassembler.push(decoded.frame);
      if (inOrder.length > 0) {
        delivered.push(...inOrder);
        this._stats.framesDelivered += inOrder.length;
      }
    }

    this.setCarryover(bytes, offset);
    return delivered;
  }

  flush(): WorkFrame<T>[] {
    if (this.carryover.length === 0) return [];
    throw new Error(
      `Cannot flush incomplete frame: ${this.carryover.length} trailing bytes`,
    );
  }

  reset(streamId?: StreamId): void {
    if (streamId === undefined) {
      this.reassembler = new FrameReassembler<T>(this.reassemblerConfig);
    } else {
      this.reassembler.reset(streamId);
    }

    this.carryover = EMPTY_BYTES;
    this._stats.carryoverBytes = 0;
  }

  get mode(): 'js' | 'wasm' {
    return this.decoder.mode;
  }

  get stats(): Readonly<WasmFrameAssemblyStats> {
    return { ...this._stats };
  }

  private concatCarryover(chunk: Uint8Array): Uint8Array {
    if (this.carryover.length === 0) return chunk;
    const merged = new Uint8Array(this.carryover.length + chunk.length);
    merged.set(this.carryover);
    merged.set(chunk, this.carryover.length);
    return merged;
  }

  private setCarryover(bytes: Uint8Array, offset: number): void {
    const remaining = bytes.length - offset;
    if (remaining <= 0) {
      this.carryover = EMPTY_BYTES;
      this._stats.carryoverBytes = 0;
      return;
    }

    if (remaining > this.maxCarryoverBytes) {
      throw new Error(
        `Carryover exceeded max size: ${remaining} > ${this.maxCarryoverBytes}`,
      );
    }

    const nextCarryover = new Uint8Array(remaining);
    nextCarryover.set(bytes.subarray(offset));
    this.carryover = nextCarryover;
    this._stats.carryoverBytes = remaining;
  }
}
