import { computeBuleMeasure } from './topology-metrics.js';
import type { BuleMeasure, PipelineMetrics, StreamId, StreamState } from './types.js';

export type FlowRegime = 'laminar' | 'transitional' | 'turbulent';

// Numeric encoding for state → counter mapping (avoids string comparison)
// active/superposed → 0, completed → 1, vented → 2, tunneled → 3, entangled → 4, pending → -1
const STATE_COUNTER: Record<StreamState, number> = {
  active: 0, superposed: 0,
  completed: 1, vented: 2, tunneled: 3, entangled: 4,
  pending: -1,
};

/**
 * Reynolds number tracking for pipeline fluidic state.
 * Uses array-based state storage + incremental counters — O(1) everything.
 * Array[streamId] = stateCode is faster than Map.get(streamId) for integer keys.
 */
export class ReynoldsTracker {
  private capacity: number;
  private intrinsicBeta1?: number;
  // Array-based storage: index = StreamId, value = counter index (or -2 for not tracked)
  // This is faster than Map for sequential integer keys
  private states: Int8Array;
  private _size = 0;

  // Incremental counters — updated on every state change
  private _active = 0;
  private _completed = 0;
  private _vented = 0;
  private _tunneled = 0;
  private _entangled = 0;

  // Counter array for branchless adjustment — index by counter ID
  private _counters = new Int32Array(5); // [active, completed, vented, tunneled, entangled]

  constructor(capacity: number, intrinsicBeta1?: number) {
    this.capacity = Math.max(1, capacity);
    this.intrinsicBeta1 = intrinsicBeta1 === undefined
      ? undefined
      : Math.max(0, Math.floor(intrinsicBeta1));
    // Pre-allocate for expected stream IDs (grow if needed)
    this.states = new Int8Array(capacity + 16).fill(-2); // -2 = not tracked
  }

  updateStream(id: StreamId, state: StreamState): void {
    // Grow if needed
    if (id >= this.states.length) {
      const newStates = new Int8Array(id * 2 + 16).fill(-2);
      newStates.set(this.states);
      this.states = newStates;
    }

    const counterIdx = STATE_COUNTER[state];
    const prev = this.states[id];

    if (prev >= 0) {
      // Decrement old counter
      this._counters[prev]--;
    } else if (prev === -2) {
      this._size++;
    }

    this.states[id] = counterIdx >= 0 ? counterIdx : -1;
    if (counterIdx >= 0) {
      this._counters[counterIdx]++;
    }

    // Keep the named fields in sync (used by getters)
    this._active = this._counters[0];
    this._completed = this._counters[1];
    this._vented = this._counters[2];
    this._tunneled = this._counters[3];
    this._entangled = this._counters[4];
  }

  removeStream(id: StreamId): void {
    if (id >= this.states.length) return;
    const prev = this.states[id];
    if (prev >= 0) {
      this._counters[prev]--;
      this._active = this._counters[0];
      this._completed = this._counters[1];
      this._vented = this._counters[2];
      this._tunneled = this._counters[3];
      this._entangled = this._counters[4];
    }
    if (prev !== -2) this._size--;
    this.states[id] = -2;
  }

  get reynoldsNumber(): number {
    return this._active / this.capacity;
  }

  get regime(): FlowRegime {
    const re = this._active / this.capacity;
    if (re < 0.3) return 'laminar';
    if (re > 0.7) return 'turbulent';
    return 'transitional';
  }

  get activeCount(): number {
    return this._active;
  }

  get idleSlots(): number {
    return Math.max(0, this.capacity - this._active);
  }

  get bettiNumber(): number {
    return Math.max(0, this._active - 1);
  }

  get buleMeasure(): BuleMeasure | undefined {
    if (this.intrinsicBeta1 === undefined) return undefined;
    return computeBuleMeasure(this.bettiNumber, this.intrinsicBeta1);
  }

  get laminarFraction(): number {
    if (this._size === 0) return 1;
    return this._completed / this._size;
  }

  metrics(): PipelineMetrics {
    const metrics: PipelineMetrics = {
      reynoldsNumber: this._active / this.capacity,
      bettiNumber: Math.max(0, this._active - 1),
      laminarFraction: this._size === 0 ? 1 : this._completed / this._size,
      activeStreams: this._active,
      capacity: this.capacity,
      completed: this._completed,
      vented: this._vented,
      tunneled: this._tunneled,
      entangled: this._entangled,
    };

    const bule = this.buleMeasure;
    if (bule) {
      metrics.intrinsicBeta1 = bule.intrinsicBeta1;
      metrics.topologicalDeficit = bule.deficit;
      metrics.wasteBules = bule.waste;
      metrics.opportunityBules = bule.opportunity;
      metrics.overforkedBules = bule.overforked;
      metrics.topologyUtilization = bule.utilization;
      metrics.topologyAssessment = bule.assessment;
    }

    return metrics;
  }
}
