import type {
  PublicSkillsExample,
  PublicSkillsFeature,
  PublicSkillsIndex,
  SkillDiscoveryEntry,
} from './types';

export interface SkillResourceDefinition {
  uri: string;
  name: string;
  description: string;
  mimeType: 'text/markdown';
}

export interface SkillReadResult {
  uri: string;
  mimeType: string;
  text: string;
}

interface SkillsIndexOptions {
  server: PublicSkillsIndex['server'];
  discovery?: PublicSkillsIndex['discovery'];
  skills: ReadonlyArray<SkillDiscoveryEntry>;
  featuredSkills?: ReadonlyArray<string>;
  features?: ReadonlyArray<PublicSkillsFeature>;
  examples?: ReadonlyArray<PublicSkillsExample>;
}

function normalizeArray(
  values: ReadonlyArray<string> | undefined
): string[] | undefined {
  if (!values || values.length === 0) {
    return undefined;
  }

  const unique = [
    ...new Set(values.map((value) => value.trim()).filter(Boolean)),
  ];
  return unique.length > 0 ? unique : undefined;
}

function normalizeSkillEntry(
  skill: SkillDiscoveryEntry
): PublicSkillsIndex['skills'][number] {
  return {
    id: skill.id,
    name: skill.name,
    uri: skill.uri,
    description: skill.description,
    tools: normalizeArray(skill.tools),
    tags: normalizeArray(skill.tags),
    publicUrl: skill.publicUrl,
    source: skill.source,
  };
}

export function buildPublicSkillsIndex(
  options: SkillsIndexOptions
): PublicSkillsIndex {
  return {
    server: options.server,
    discovery: options.discovery ?? {},
    skills: options.skills.map(normalizeSkillEntry),
    featuredSkills:
      options.featuredSkills && options.featuredSkills.length > 0
        ? [...new Set(options.featuredSkills)]
        : undefined,
    features:
      options.features && options.features.length > 0
        ? options.features.map((feature) => ({
            ...feature,
            tools: normalizeArray(feature.tools),
            resources: normalizeArray(feature.resources),
          }))
        : undefined,
    examples:
      options.examples && options.examples.length > 0
        ? options.examples.map((example) => ({ ...example }))
        : undefined,
  };
}

export function buildSkillsListPayload(options: SkillsIndexOptions): {
  skills: PublicSkillsIndex['skills'];
} {
  return {
    skills: buildPublicSkillsIndex(options).skills,
  };
}

export function buildSkillResources(
  skills: ReadonlyArray<SkillDiscoveryEntry>
): SkillResourceDefinition[] {
  return skills.map((skill) => ({
    uri: skill.uri,
    name: skill.name,
    description: skill.description,
    mimeType: 'text/markdown',
  }));
}

export function renderSkillMarkdown(skill: SkillDiscoveryEntry): string {
  if (typeof skill.content === 'string' && skill.content.trim().length > 0) {
    return skill.content;
  }

  const lines = [
    `# ${skill.name}`,
    '',
    '## When to use',
    skill.description,
    '',
    '## Workflow',
    '1. Confirm the goal and required inputs.',
    '2. Select the tools listed below that best fit the task.',
    '3. Execute the tools in a sensible order, preserving context between steps.',
    '4. Summarize the outcome clearly and call out any missing information.',
    '',
    '## Tool sequence',
  ];

  const tools = normalizeArray(skill.tools) ?? [];
  if (tools.length > 0) {
    for (const tool of tools) {
      lines.push(`- \`${tool}\``);
    }
  } else {
    lines.push('- No explicit tool mapping declared.');
  }

  lines.push('', '## Failure handling');
  lines.push(
    '- If a tool call fails, report the failing step and retry only with corrected inputs.'
  );
  lines.push(
    '- If required context is missing, ask for that context before making assumptions.'
  );

  lines.push('', '## Examples');
  lines.push(
    `- Use this skill when you need to complete the "${skill.name}" workflow reliably.`
  );

  const tags = normalizeArray(skill.tags);
  if (tags && tags.length > 0) {
    lines.push('', '## Tags');
    for (const tag of tags) {
      lines.push(`- ${tag}`);
    }
  }

  return lines.join('\n');
}

function buildSkillMetadata(skill: SkillDiscoveryEntry): string {
  const lines = [`name: ${skill.name}`, `description: ${skill.description}`];

  const tags = normalizeArray(skill.tags);
  if (tags && tags.length > 0) {
    lines.push(`metadata.tags: ${tags.join(', ')}`);
  }

  const tools = normalizeArray(skill.tools);
  if (tools && tools.length > 0) {
    lines.push(`allowed-tools: ${tools.join(' ')}`);
  }

  return lines.join('\n') + '\n';
}

function findSkillByUri(
  skills: ReadonlyArray<SkillDiscoveryEntry>,
  uri: string
): SkillDiscoveryEntry | null {
  const normalizedUri = uri.trim();
  const exact = skills.find(
    (entry) =>
      normalizedUri === entry.uri ||
      normalizedUri === `${entry.uri}/metadata` ||
      normalizedUri === `${entry.uri}/full`
  );

  if (exact) {
    return exact;
  }

  if (!normalizedUri.startsWith('skill://')) {
    return null;
  }

  const withoutPrefix = normalizedUri.slice('skill://'.length);
  const segments = withoutPrefix
    .split('/')
    .map((segment) => segment.trim())
    .filter(Boolean);

  if (segments.length === 0) {
    return null;
  }

  const candidateSlug =
    segments[segments.length - 1] === 'metadata' ||
    segments[segments.length - 1] === 'full'
      ? segments[segments.length - 2]
      : segments[segments.length - 1];

  if (!candidateSlug) {
    return null;
  }

  return (
    skills.find((entry) => {
      const entrySegments = entry.uri
        .slice('skill://'.length)
        .split('/')
        .map((segment) => segment.trim())
        .filter(Boolean);
      const entrySlug = entrySegments[entrySegments.length - 1];
      return entrySlug?.toLowerCase() === candidateSlug.toLowerCase();
    }) ?? null
  );
}

export function readSkillResource(
  skills: ReadonlyArray<SkillDiscoveryEntry>,
  uri: string
): SkillReadResult | null {
  const normalizedUri = uri.trim();
  const skill = findSkillByUri(skills, normalizedUri);

  if (!skill) {
    return null;
  }

  if (normalizedUri.endsWith('/metadata')) {
    return {
      uri: normalizedUri,
      mimeType: 'text/yaml',
      text: buildSkillMetadata(skill),
    };
  }

  return {
    uri: normalizedUri,
    mimeType: 'text/markdown',
    text: renderSkillMarkdown(skill),
  };
}

export function getSkillByName(
  skills: ReadonlyArray<SkillDiscoveryEntry>,
  skillName: string
): SkillDiscoveryEntry | null {
  const normalizedName = skillName.trim().toLowerCase();
  return (
    skills.find((skill) => {
      const candidateNames = [
        skill.name,
        skill.id,
        skill.uri.split('/').pop() ?? '',
      ];
      return candidateNames.some(
        (candidate) => candidate.trim().toLowerCase() === normalizedName
      );
    }) ?? null
  );
}
