import type { WorkFrame, StreamId } from './types.js';
import { FORK, RACE, FOLD, VENT, FIN } from './types.js';

export const HEADER_SIZE = 10;
export const MAX_PAYLOAD_LENGTH = 0xffffff;

// Reuse encoder/decoder — allocation cost amortized
const encoder = new TextEncoder();
const decoder = new TextDecoder();

/**
 * Encode a WorkFrame to Aeon Flow's 10-byte wire format.
 */
export function encodeFlowFrame<T>(frame: WorkFrame<T>, flags: number = 0): Uint8Array {
  const payloadBytes = encoder.encode(JSON.stringify(frame.payload));
  const payloadLen = payloadBytes.length;

  if (payloadLen > MAX_PAYLOAD_LENGTH) {
    throw new Error(`Payload too large: ${payloadLen} > ${MAX_PAYLOAD_LENGTH}`);
  }

  const totalLen = HEADER_SIZE + payloadLen;
  const buffer = new ArrayBuffer(totalLen);
  const view = new DataView(buffer);
  const bytes = new Uint8Array(buffer);

  view.setUint16(0, frame.streamId);
  view.setUint32(2, frame.sequence);
  view.setUint8(6, flags);
  view.setUint8(7, (payloadLen >> 16) & 0xff);
  view.setUint8(8, (payloadLen >> 8) & 0xff);
  view.setUint8(9, payloadLen & 0xff);

  bytes.set(payloadBytes, HEADER_SIZE);
  return bytes;
}

/**
 * Decode a WorkFrame from Aeon Flow's 10-byte wire format.
 * Supports offset parameter to avoid slice() in batch decode.
 */
export function decodeFlowFrame<T>(
  bytes: Uint8Array,
  offset: number = 0,
): { frame: WorkFrame<T>; flags: number; bytesRead: number } {
  if (bytes.length - offset < HEADER_SIZE) {
    throw new Error(`Buffer too small: ${bytes.length - offset} < ${HEADER_SIZE}`);
  }

  const view = new DataView(bytes.buffer, bytes.byteOffset + offset, bytes.byteLength - offset);

  const streamId = view.getUint16(0);
  const sequence = view.getUint32(2);
  const flags = view.getUint8(6);
  const length = (view.getUint8(7) << 16) | (view.getUint8(8) << 8) | view.getUint8(9);

  const totalNeeded = HEADER_SIZE + length;
  if (bytes.length - offset < totalNeeded) {
    throw new Error(`Buffer incomplete: have ${bytes.length - offset}, need ${totalNeeded}`);
  }

  const payload = length > 0
    ? (JSON.parse(decoder.decode(
        bytes.subarray(offset + HEADER_SIZE, offset + HEADER_SIZE + length),
      )) as T)
    : (undefined as unknown as T);

  return {
    frame: { streamId, sequence, payload, emittedAt: Date.now() },
    flags,
    bytesRead: totalNeeded,
  };
}

/**
 * Encode a batch of frames into a single buffer.
 * Two-pass: first pass encodes payloads + computes exact size,
 * second pass writes headers + copies payloads into single allocation.
 */
export function encodeBatch<T>(
  frames: { frame: WorkFrame<T>; flags?: number }[],
): Uint8Array {
  const len = frames.length;
  if (len === 0) return new Uint8Array(0);

  // First pass: encode all payloads and compute exact total size
  const payloads: Uint8Array[] = new Array(len);
  let totalLength = len * HEADER_SIZE;

  for (let i = 0; i < len; i++) {
    const p = encoder.encode(JSON.stringify(frames[i].frame.payload));
    payloads[i] = p;
    totalLength += p.length;
  }

  // Single allocation for the entire batch (exact size — no trim needed)
  const result = new Uint8Array(totalLength);
  const view = new DataView(result.buffer);
  let offset = 0;

  for (let i = 0; i < len; i++) {
    const { frame, flags: f } = frames[i];
    const payloadLen = payloads[i].length;
    const fl = f ?? 0;

    view.setUint16(offset, frame.streamId);
    view.setUint32(offset + 2, frame.sequence);
    view.setUint8(offset + 6, fl);
    view.setUint8(offset + 7, (payloadLen >> 16) & 0xff);
    view.setUint8(offset + 8, (payloadLen >> 8) & 0xff);
    view.setUint8(offset + 9, payloadLen & 0xff);

    result.set(payloads[i], offset + HEADER_SIZE);
    offset += HEADER_SIZE + payloadLen;
  }

  return result;
}

/**
 * Decode all frames from a batch buffer.
 * Inlined decode loop — avoids per-frame function call overhead and redundant bounds checks.
 * Zero-copy: uses DataView + subarray for payload access.
 * Batch timestamp: single Date.now() for all decoded frames.
 */
export function decodeBatch<T>(
  bytes: Uint8Array,
): { frame: WorkFrame<T>; flags: number }[] {
  const totalLen = bytes.length;
  if (totalLen === 0) return [];

  // Estimate frame count from average payload size (heuristic: ~30 bytes avg)
  const estimatedFrames = Math.max(4, Math.ceil(totalLen / (HEADER_SIZE + 30)));
  const results: { frame: WorkFrame<T>; flags: number }[] = new Array(estimatedFrames);
  const baseView = new DataView(bytes.buffer, bytes.byteOffset, bytes.byteLength);
  const ts = Date.now(); // Single timestamp for entire batch
  let offset = 0;
  let count = 0;

  while (offset < totalLen) {
    const streamId = baseView.getUint16(offset);
    const sequence = baseView.getUint32(offset + 2);
    const flags = baseView.getUint8(offset + 6);
    const length = (baseView.getUint8(offset + 7) << 16) |
                   (baseView.getUint8(offset + 8) << 8) |
                   baseView.getUint8(offset + 9);

    const payload = length > 0
      ? (JSON.parse(decoder.decode(
          bytes.subarray(offset + HEADER_SIZE, offset + HEADER_SIZE + length),
        )) as T)
      : (undefined as unknown as T);

    if (count >= results.length) {
      // Grow if estimate was too low (rare for well-estimated batches)
      results.push({ frame: { streamId, sequence, payload, emittedAt: ts }, flags });
    } else {
      results[count] = { frame: { streamId, sequence, payload, emittedAt: ts }, flags };
    }
    count++;

    offset += HEADER_SIZE + length;
  }

  // Trim to actual count
  if (count < results.length) results.length = count;
  return results;
}

export { FORK, RACE, FOLD, VENT, FIN };
