// ─── Identity ───────────────────────────────────────────────────────────────

export type StreamId = number;

export type StreamState =
  | 'pending'
  | 'superposed'
  | 'active'
  | 'completed'
  | 'vented'
  | 'tunneled'
  | 'entangled';

// ─── Wire format flags (matching Aeon Flow) ─────────────────────────────────

export const FORK = 0x01;
export const RACE = 0x02;
export const FOLD = 0x04;
export const VENT = 0x08;
export const FIN = 0x10;

// ─── Self-describing work unit ──────────────────────────────────────────────

export interface WorkFrame<T = unknown> {
  streamId: StreamId;
  sequence: number;
  payload: T;
  metadata?: Record<string, unknown>;
  emittedAt: number;
}

// ─── Stream — a single path in the DAG ──────────────────────────────────────

export interface Stream<T = unknown> {
  id: StreamId;
  parentId: StreamId | null;
  childIds: StreamId[];
  state: StreamState;
  work: () => Promise<T>;
  controller: AbortController;
  result?: T;
  error?: Error;
  createdAt: number;
  startedAt?: number;
  completedAt?: number;
  entangledWith?: StreamId[];
}

// ─── Fold strategies ────────────────────────────────────────────────────

export type FoldStrategy<T, R = T> =
  | { type: 'winner-take-all'; selector?: (results: Map<StreamId, T>) => T }
  | { type: 'quorum'; threshold: number; agree: (a: T, b: T) => boolean }
  | { type: 'merge-all'; merge: (results: Map<StreamId, T>) => R }
  | {
      type: 'consensus';
      mode: 'constructive' | 'destructive';
      compare: (a: T, b: T) => boolean;
    }
  | {
      type: 'weighted';
      weights: Map<StreamId, number>;
      merge: (weighted: [T, number][]) => R;
    }
  | {
      type: 'custom';
      fold: (results: Map<StreamId, T>, vented: Set<StreamId>) => R;
    };

// ─── Predicates ─────────────────────────────────────────────────────────────

export type VentPredicate<T> = (result: T, stream: Stream<T>) => boolean;
export type TunnelPredicate<T> = (partial: T, stream: Stream<T>) => boolean;

// ─── Search configuration (Grover-style) ────────────────────────────────────

export interface SearchConfig<T> {
  width: number;
  oracle: (candidate: T) => number;
  mutate: (survivor: T, generation: number) => T;
  convergenceThreshold?: number;
  maxIterations?: number;
  strategy?: 'amplify-mutate' | 'oracle-guided' | 'filter';
}

// ─── Pipeline metrics — fluidic state ───────────────────────────────────────

export interface PipelineMetrics {
  reynoldsNumber: number;
  bettiNumber: number;
  laminarFraction: number;
  activeStreams: number;
  capacity: number;
  completed: number;
  vented: number;
  tunneled: number;
  entangled: number;
  intrinsicBeta1?: number;
  topologicalDeficit?: number;
  wasteBules?: number;
  opportunityBules?: number;
  overforkedBules?: number;
  topologyUtilization?: number;
  topologyAssessment?: string;
}

// ─── Pipeline configuration ─────────────────────────────────────────────────

export interface PipelineConfig {
  capacity?: number;
  highWaterMark?: number;
  turbulentMultiplexing?: boolean;
  onIdleSlot?: (idleCount: number) => Stream[] | void;
  intrinsicBeta1?: number;
}

// ─── Topology deficit diagnostics ───────────────────────────────────────────

export interface BuleMeasure {
  intrinsicBeta1: number;
  actualBeta1: number;
  deficit: number;
  waste: number;
  opportunity: number;
  overforked: number;
  utilization: number;
  assessment: string;
}
