import type { Stream, StreamId, TunnelPredicate } from './types.js';
import { ventStream } from './vent.js';

/**
 * Tunneling: early exit when confidence threshold is met.
 * A stream can "tunnel" through the barrier of waiting for all results
 * by producing a result that satisfies the predicate before other streams finish.
 *
 * Returns the first result that passes the predicate, venting all others.
 */
export async function tunnel<T>(
  streams: Stream<T>[],
  predicate: TunnelPredicate<T>,
  allStreams?: Map<StreamId, Stream<unknown>>,
): Promise<{ tunneled: StreamId; result: T } | null> {
  return new Promise((resolve) => {
    let settled = false;
    let completedCount = 0;

    for (const stream of streams) {
      // Watch for each stream's completion
      const originalWork = stream.work;
      stream.work = async () => {
        const result = await originalWork();

        if (!settled && predicate(result, stream)) {
          settled = true;
          stream.state = 'tunneled';
          stream.result = result;
          stream.completedAt = Date.now();

          // Vent remaining active streams
          for (const other of streams) {
            if (other.id !== stream.id && other.state !== 'completed' && other.state !== 'tunneled') {
              ventStream(other, allStreams);
            }
          }

          resolve({ tunneled: stream.id, result });
        }

        completedCount++;
        if (completedCount === streams.length && !settled) {
          resolve(null); // No tunnel condition met
        }

        return result;
      };
    }
  });
}
