import { computeBuleMeasure } from './topology-metrics.js';
import type { BuleMeasure } from './types.js';

export interface SamplerConfig {
  intrinsicBeta1: number;
  maxSamples?: number;
}

/** Point-in-time runtime topology measurement. */
export interface Sample {
  timestamp: number;
  activeForks: number;
  activeParallelPaths: number;
  beta1: number;
  deficit: number;
  waste: number;
  opportunity: number;
  overforked: number;
  utilization: number;
  totalForks: number;
  totalFolds: number;
  totalVents: number;
  totalRaces: number;
}

/** Aggregate runtime report for sampled topology dynamics. */
export interface SamplerReport {
  intrinsicBeta1: number;
  sampleCount: number;
  meanBeta1: number;
  peakBeta1: number;
  meanDeficit: number;
  meanWaste: number;
  meanOpportunity: number;
  meanOverforked: number;
  meanUtilization: number;
  peakUtilization: number;
  totals: { forks: number; folds: number; vents: number; races: number };
  ventRatio: number;
  efficiency: number;
  assessment: string;
  currentBule: BuleMeasure;
  samples: Sample[];
}

interface ActiveFork {
  id: string;
  paths: Set<string>;
  startTime: number;
  raceWinner?: string;
}

/**
 * Runtime sampler for topological deficit, waste, and opportunity.
 */
export class TopologySampler {
  private readonly config: Required<SamplerConfig>;
  private readonly activeForks = new Map<string, ActiveFork>();
  private readonly samples: Sample[] = [];
  private totalForks = 0;
  private totalFolds = 0;
  private totalVents = 0;
  private totalRaces = 0;

  constructor(config: SamplerConfig) {
    this.config = {
      maxSamples: 1000,
      ...config,
    };
  }

  /** Record a fork event: one computation split into multiple paths. */
  fork(id: string, paths: string[]): void {
    this.activeForks.set(id, {
      id,
      paths: new Set(paths),
      startTime: Date.now(),
    });
    this.totalForks++;
    this.recordSample();
  }

  /** Record race winner for a fork. */
  race(id: string, winnerPath: string): void {
    const fork = this.activeForks.get(id);
    if (fork) {
      fork.raceWinner = winnerPath;
    }
    this.totalRaces++;
    this.recordSample();
  }

  /** Record vented path. */
  vent(id: string, path: string): void {
    const fork = this.activeForks.get(id);
    if (fork) {
      fork.paths.delete(path);
    }
    this.totalVents++;
    this.recordSample();
  }

  /** Record fold completion for a fork. */
  fold(id: string): void {
    this.activeForks.delete(id);
    this.totalFolds++;
    this.recordSample();
  }

  /** Manually sample without recording a new lifecycle event. */
  sample(): Sample {
    return this.recordSample();
  }

  /** Current instantaneous beta1 from active fork sets. */
  currentBeta1(): number {
    let beta1 = 0;
    for (const fork of this.activeForks.values()) {
      beta1 += Math.max(0, fork.paths.size - 1);
    }
    return beta1;
  }

  /** Current instantaneous signed Bule diagnostics. */
  currentBule(): BuleMeasure {
    return computeBuleMeasure(this.currentBeta1(), this.config.intrinsicBeta1);
  }

  /** Current instantaneous signed deficit in Bules. */
  currentDeficit(): number {
    return this.currentBule().deficit;
  }

  /** Aggregate report over retained samples. */
  report(): SamplerReport {
    const n = this.samples.length;
    const currentBule = this.currentBule();

    if (n === 0) {
      return {
        intrinsicBeta1: this.config.intrinsicBeta1,
        sampleCount: 0,
        meanBeta1: 0,
        peakBeta1: 0,
        meanDeficit: currentBule.deficit,
        meanWaste: currentBule.waste,
        meanOpportunity: currentBule.opportunity,
        meanOverforked: currentBule.overforked,
        meanUtilization: currentBule.utilization,
        peakUtilization: currentBule.utilization,
        totals: { forks: 0, folds: 0, vents: 0, races: 0 },
        ventRatio: 0,
        efficiency: 0,
        assessment: 'No samples collected',
        currentBule,
        samples: [],
      };
    }

    let sumBeta1 = 0;
    let sumDeficit = 0;
    let sumWaste = 0;
    let sumOpportunity = 0;
    let sumOverforked = 0;
    let sumUtilization = 0;
    let peakBeta1 = 0;
    let peakUtilization = 0;

    for (let i = 0; i < n; i++) {
      const sample = this.samples[i];
      const weight = i < n - 1
        ? this.samples[i + 1].timestamp - sample.timestamp
        : 1;
      const effectiveWeight = Math.max(1, weight);

      sumBeta1 += sample.beta1 * effectiveWeight;
      sumDeficit += sample.deficit * effectiveWeight;
      sumWaste += sample.waste * effectiveWeight;
      sumOpportunity += sample.opportunity * effectiveWeight;
      sumOverforked += sample.overforked * effectiveWeight;
      sumUtilization += sample.utilization * effectiveWeight;

      if (sample.beta1 > peakBeta1) peakBeta1 = sample.beta1;
      if (sample.utilization > peakUtilization) peakUtilization = sample.utilization;
    }

    const totalWeight = n > 1
      ? this.samples[n - 1].timestamp - this.samples[0].timestamp + 1
      : 1;

    const meanBeta1 = sumBeta1 / totalWeight;
    const meanDeficit = sumDeficit / totalWeight;
    const meanWaste = sumWaste / totalWeight;
    const meanOpportunity = sumOpportunity / totalWeight;
    const meanOverforked = sumOverforked / totalWeight;
    const meanUtilization = sumUtilization / totalWeight;

    const terminalEvents = this.totalRaces + this.totalVents;
    const ventRatio = terminalEvents > 0 ? this.totalVents / terminalEvents : 0;
    const efficiency = terminalEvents > 0 ? this.totalRaces / terminalEvents : 0;

    let assessment: string;
    if (meanOpportunity === 0 && meanOverforked === 0) {
      assessment = `Topology matched: mean utilization ${(meanUtilization * 100).toFixed(1)}%, mean deficit ${meanDeficit.toFixed(2)} B`;
    } else if (meanOverforked > 0) {
      assessment = `Over-forked: mean overfork ${meanOverforked.toFixed(2)} B, mean utilization ${(meanUtilization * 100).toFixed(1)}%`;
    } else if (meanUtilization >= 0.7) {
      assessment = `Near-optimal: mean opportunity ${meanOpportunity.toFixed(2)} B, peak beta1 ${peakBeta1}`;
    } else if (meanUtilization >= 0.3) {
      assessment = `Underutilized: mean opportunity ${meanOpportunity.toFixed(2)} B, mean beta1 ${meanBeta1.toFixed(2)}`;
    } else {
      assessment = `Sequential bottleneck: mean opportunity ${meanOpportunity.toFixed(2)} B`;
    }

    return {
      intrinsicBeta1: this.config.intrinsicBeta1,
      sampleCount: n,
      meanBeta1,
      peakBeta1,
      meanDeficit,
      meanWaste,
      meanOpportunity,
      meanOverforked,
      meanUtilization,
      peakUtilization,
      totals: {
        forks: this.totalForks,
        folds: this.totalFolds,
        vents: this.totalVents,
        races: this.totalRaces,
      },
      ventRatio,
      efficiency,
      assessment,
      currentBule,
      samples: [...this.samples],
    };
  }

  /** Reset all sampler state. */
  reset(): void {
    this.activeForks.clear();
    this.samples.length = 0;
    this.totalForks = 0;
    this.totalFolds = 0;
    this.totalVents = 0;
    this.totalRaces = 0;
  }

  private recordSample(): Sample {
    let activeParallelPaths = 0;
    let beta1 = 0;
    for (const fork of this.activeForks.values()) {
      activeParallelPaths += fork.paths.size;
      beta1 += Math.max(0, fork.paths.size - 1);
    }

    const bule = computeBuleMeasure(beta1, this.config.intrinsicBeta1);
    const sample: Sample = {
      timestamp: Date.now(),
      activeForks: this.activeForks.size,
      activeParallelPaths,
      beta1,
      deficit: bule.deficit,
      waste: bule.waste,
      opportunity: bule.opportunity,
      overforked: bule.overforked,
      utilization: bule.utilization,
      totalForks: this.totalForks,
      totalFolds: this.totalFolds,
      totalVents: this.totalVents,
      totalRaces: this.totalRaces,
    };

    this.samples.push(sample);
    if (this.samples.length > this.config.maxSamples) {
      this.samples.shift();
    }

    return sample;
  }
}

