import type { ComputationGraph, TopologyReport } from './topology-analyzer.js';

/**
 * Options for Cypher export.
 */
export interface CypherExportOptions {
  /** Label for nodes (default: "ComputationNode") */
  nodeLabel?: string;
  /** Relationship type (default: "FLOWS_TO") */
  relType?: string;
  /** Whether to include metrics in the output */
  includeMetrics?: boolean;
}

/**
 * Exporter for ComputationGraph to Neo4j Cypher.
 */
export class CypherExporter {
  /**
   * Converts a ComputationGraph to Cypher MERGE statements.
   */
  static toCypher(graph: ComputationGraph, options: CypherExportOptions = {}): string {
    const nodeLabel = options.nodeLabel || 'ComputationNode';
    const relType = options.relType || 'FLOWS_TO';
    const lines: string[] = ['// Aeon Pipeline Export'];

    // Nodes
    for (const node of graph.nodes) {
      const props: Record<string, any> = {
        id: node.id,
        label: node.label || node.id,
        type: node.type || 'process'
      };
      
      const propsStr = this.propsToCypher(props);
      lines.push(`MERGE (n:${nodeLabel} {id: '${node.id}'}) ON CREATE SET n = ${propsStr} ON MATCH SET n = ${propsStr};`);
    }

    // Edges
    for (const edge of graph.edges) {
      const propsStr = edge.label ? ` { label: '${edge.label}' }` : '';
      lines.push(`MATCH (a:${nodeLabel} {id: '${edge.from}'}), (b:${nodeLabel} {id: '${edge.to}'}) MERGE (a)-[r:${relType}${propsStr}]->(b);`);
    }

    return lines.join('\n');
  }

  /**
   * Converts a TopologyReport to a Cypher MERGE statement for a metrics node.
   */
  static toCypherReport(report: TopologyReport, graphId: string): string {
    const props: Record<string, any> = {
      graphId,
      beta0: report.betti.beta0,
      beta1: report.betti.beta1,
      beta2: report.betti.beta2,
      nodeCount: report.nodeCount,
      edgeCount: report.edgeCount,
      isDAG: report.isDAG,
      timestamp: new Date().toISOString()
    };

    if (report.deficit) {
      props.buleDeficit = report.deficit.deficit;
      props.buleWaste = report.deficit.waste;
      props.buleOpportunity = report.deficit.opportunity;
      props.buleOverforked = report.deficit.overforked;
      props.buleUtilization = report.deficit.utilization;
    }

    const propsStr = this.propsToCypher(props);
    return `MERGE (m:PipelineMetrics {graphId: '${graphId}'}) ON CREATE SET m = ${propsStr} ON MATCH SET m = ${propsStr};`;
  }

  private static propsToCypher(obj: Record<string, any>): string {
    const parts = Object.entries(obj).map(([k, v]) => {
      const val = typeof v === 'string' ? `'${v.replace(/'/g, "\\'")}'` : v;
      return `${k}: ${val}`;
    });
    return `{ ${parts.join(', ')} }`;
  }
}
