import { computeBuleMeasure } from './topology-metrics.js';
import type { BuleMeasure } from './types.js';

/** A node in a computation graph. */
export interface ComputationNode {
  id: string;
  label?: string;
  type?: 'source' | 'sink' | 'fork' | 'join' | 'process';
}

/** A directed edge in a computation graph. */
export interface ComputationEdge {
  from: string;
  to: string;
  label?: string;
}

/** Graph input for topological analysis. */
export interface ComputationGraph {
  nodes: ComputationNode[];
  edges: ComputationEdge[];
  intrinsicBeta1?: number;
}

/** Betti numbers for a graph. */
export interface BettiNumbers {
  beta0: number;
  beta1: number;
  beta2: number;
}

/** A detected fork/join pair. */
export interface ForkJoinPair {
  forkNode: string;
  joinNode: string;
  parallelPaths: number;
  beta1Contribution: number;
}

/** Signed Bule diagnostics for a graph. */
export type DeficitReport = BuleMeasure;

/** Complete analysis report. */
export interface TopologyReport {
  betti: BettiNumbers;
  forkJoinPairs: ForkJoinPair[];
  deficit?: DeficitReport;
  nodeCount: number;
  edgeCount: number;
  isDAG: boolean;
  reynoldsEstimate?: number;
}

/**
 * Static topology analyzer for computation graphs.
 *
 * Computes:
 *  - beta0 (connected components)
 *  - beta1 (independent forked paths)
 *  - beta2 (dead-end voids)
 *  - signed Bule deficit (if intrinsic beta1 is provided)
 */
export class TopologyAnalyzer {
  static analyze(graph: ComputationGraph): TopologyReport {
    const adjacency = buildAdjacency(graph);
    const reverseAdj = buildReverseAdjacency(graph);
    const nodeIds = graph.nodes.map(node => node.id);

    const beta0 = computeBeta0(nodeIds, adjacency);
    const isDAG = checkDAG(nodeIds, adjacency);
    const forkJoinPairs = detectForkJoinPairs(nodeIds, adjacency);
    const beta1 = computeBeta1(graph.nodes.length, graph.edges.length, beta0, forkJoinPairs);
    const beta2 = estimateBeta2(nodeIds, adjacency, reverseAdj);

    const report: TopologyReport = {
      betti: { beta0, beta1, beta2 },
      forkJoinPairs,
      nodeCount: graph.nodes.length,
      edgeCount: graph.edges.length,
      isDAG,
    };

    if (graph.intrinsicBeta1 !== undefined) {
      report.deficit = computeBuleMeasure(beta1, graph.intrinsicBeta1);
    }

    return report;
  }

  /** Quick signed Bule deficit. */
  static deficit(graph: ComputationGraph, intrinsicBeta1: number): number {
    const report = TopologyAnalyzer.analyze({ ...graph, intrinsicBeta1 });
    return report.deficit!.deficit;
  }

  /** Full Bule measure for a graph. */
  static bule(graph: ComputationGraph, intrinsicBeta1: number): BuleMeasure {
    const report = TopologyAnalyzer.analyze({ ...graph, intrinsicBeta1 });
    return report.deficit!;
  }

  /** Convenience builder for a fork/race/fold graph. */
  static fromForkRaceFold(config: {
    forkWidth: number;
    stagesPerPath?: number;
    intrinsicBeta1?: number;
  }): ComputationGraph {
    const forkWidth = Math.max(1, Math.floor(config.forkWidth));
    const stagesPerPath = Math.max(1, Math.floor(config.stagesPerPath ?? 1));

    const nodes: ComputationNode[] = [
      { id: 'source', type: 'source' },
      { id: 'fork', type: 'fork' },
      { id: 'join', type: 'join' },
      { id: 'sink', type: 'sink' },
    ];

    const edges: ComputationEdge[] = [
      { from: 'source', to: 'fork' },
      { from: 'join', to: 'sink' },
    ];

    for (let path = 0; path < forkWidth; path++) {
      const pathNodes: string[] = [];

      for (let stage = 0; stage < stagesPerPath; stage++) {
        const id = `path-${path}-stage-${stage}`;
        nodes.push({
          id,
          type: 'process',
          label: `Path ${path} Stage ${stage}`,
        });
        pathNodes.push(id);
      }

      edges.push({ from: 'fork', to: pathNodes[0] });
      for (let stage = 1; stage < pathNodes.length; stage++) {
        edges.push({ from: pathNodes[stage - 1], to: pathNodes[stage] });
      }
      edges.push({ from: pathNodes[pathNodes.length - 1], to: 'join' });
    }

    return {
      nodes,
      edges,
      intrinsicBeta1: config.intrinsicBeta1,
    };
  }

  /** Convenience builder for a sequential pipeline graph. */
  static sequential(stages: number, intrinsicBeta1?: number): ComputationGraph {
    const normalizedStages = Math.max(1, Math.floor(stages));
    const nodes: ComputationNode[] = [];
    const edges: ComputationEdge[] = [];

    for (let i = 0; i < normalizedStages; i++) {
      nodes.push({
        id: `stage-${i}`,
        type: 'process',
        label: `Stage ${i}`,
      });

      if (i > 0) {
        edges.push({ from: `stage-${i - 1}`, to: `stage-${i}` });
      }
    }

    return { nodes, edges, intrinsicBeta1 };
  }
}

function buildAdjacency(graph: ComputationGraph): Map<string, string[]> {
  const adjacency = new Map<string, string[]>();
  for (const node of graph.nodes) {
    adjacency.set(node.id, []);
  }
  for (const edge of graph.edges) {
    const list = adjacency.get(edge.from);
    if (list) list.push(edge.to);
  }
  return adjacency;
}

function buildReverseAdjacency(graph: ComputationGraph): Map<string, string[]> {
  const reverse = new Map<string, string[]>();
  for (const node of graph.nodes) {
    reverse.set(node.id, []);
  }
  for (const edge of graph.edges) {
    const list = reverse.get(edge.to);
    if (list) list.push(edge.from);
  }
  return reverse;
}

function computeBeta0(nodeIds: string[], adjacency: Map<string, string[]>): number {
  const parent = new Map<string, string>();
  const rank = new Map<string, number>();

  for (const id of nodeIds) {
    parent.set(id, id);
    rank.set(id, 0);
  }

  function find(id: string): string {
    let root = id;
    while (parent.get(root) !== root) {
      root = parent.get(root)!;
    }

    let current = id;
    while (current !== root) {
      const next = parent.get(current)!;
      parent.set(current, root);
      current = next;
    }

    return root;
  }

  function union(a: string, b: string): void {
    const rootA = find(a);
    const rootB = find(b);

    if (rootA === rootB) return;

    const rankA = rank.get(rootA)!;
    const rankB = rank.get(rootB)!;

    if (rankA < rankB) {
      parent.set(rootA, rootB);
    } else if (rankA > rankB) {
      parent.set(rootB, rootA);
    } else {
      parent.set(rootB, rootA);
      rank.set(rootA, rankA + 1);
    }
  }

  for (const [from, tos] of adjacency) {
    for (const to of tos) {
      union(from, to);
    }
  }

  const roots = new Set<string>();
  for (const id of nodeIds) {
    roots.add(find(id));
  }

  return roots.size;
}

function checkDAG(nodeIds: string[], adjacency: Map<string, string[]>): boolean {
  const inDegree = new Map<string, number>();
  for (const id of nodeIds) {
    inDegree.set(id, 0);
  }

  for (const [, tos] of adjacency) {
    for (const to of tos) {
      inDegree.set(to, (inDegree.get(to) || 0) + 1);
    }
  }

  const queue: string[] = [];
  for (const [id, degree] of inDegree) {
    if (degree === 0) queue.push(id);
  }

  let processed = 0;
  while (queue.length > 0) {
    const node = queue.shift()!;
    processed++;

    for (const neighbor of adjacency.get(node) || []) {
      const nextDegree = inDegree.get(neighbor)! - 1;
      inDegree.set(neighbor, nextDegree);
      if (nextDegree === 0) queue.push(neighbor);
    }
  }

  return processed === nodeIds.length;
}

function detectForkJoinPairs(nodeIds: string[], adjacency: Map<string, string[]>): ForkJoinPair[] {
  const pairs: ForkJoinPair[] = [];

  for (const id of nodeIds) {
    const children = adjacency.get(id) || [];
    if (children.length <= 1) continue;

    const reachablePerChild = children.map((child) => {
      const reachable = new Set<string>();
      const queue = [child];

      while (queue.length > 0) {
        const node = queue.shift()!;
        if (reachable.has(node)) continue;

        reachable.add(node);
        for (const next of adjacency.get(node) || []) {
          queue.push(next);
        }
      }

      return reachable;
    });

    if (reachablePerChild.length === 0) continue;

    const intersection = new Set<string>();
    for (const candidate of reachablePerChild[0]) {
      if (reachablePerChild.every(set => set.has(candidate))) {
        intersection.add(candidate);
      }
    }

    if (intersection.size === 0) continue;

    let nearestJoin: string | null = null;
    let nearestDistance = Number.POSITIVE_INFINITY;
    const queue: Array<[string, number]> = [[id, 0]];
    const seen = new Set<string>();

    while (queue.length > 0) {
      const [node, distance] = queue.shift()!;
      if (seen.has(node)) continue;
      seen.add(node);

      if (intersection.has(node) && node !== id) {
        if (distance < nearestDistance) {
          nearestJoin = node;
          nearestDistance = distance;
        }
        break;
      }

      for (const next of adjacency.get(node) || []) {
        queue.push([next, distance + 1]);
      }
    }

    if (!nearestJoin) continue;

    pairs.push({
      forkNode: id,
      joinNode: nearestJoin,
      parallelPaths: children.length,
      beta1Contribution: children.length - 1,
    });
  }

  return pairs;
}

function computeBeta1(
  nodeCount: number,
  edgeCount: number,
  beta0: number,
  forkJoinPairs: ForkJoinPair[],
): number {
  if (forkJoinPairs.length > 0) {
    return forkJoinPairs.reduce((total, pair) => total + pair.beta1Contribution, 0);
  }

  return Math.max(0, edgeCount - nodeCount + beta0);
}

function estimateBeta2(
  nodeIds: string[],
  adjacency: Map<string, string[]>,
  reverseAdj: Map<string, string[]>,
): number {
  const sources = nodeIds.filter(id => (reverseAdj.get(id) || []).length === 0);
  const sinks = nodeIds.filter(id => (adjacency.get(id) || []).length === 0);

  if (sources.length === 0 || sinks.length <= 1) return 0;

  let primarySink = sinks[0];
  let primaryReachSize = 0;

  for (const sink of sinks) {
    const reachable = new Set<string>();
    const queue = [sink];

    while (queue.length > 0) {
      const node = queue.shift()!;
      if (reachable.has(node)) continue;

      reachable.add(node);
      for (const previous of reverseAdj.get(node) || []) {
        queue.push(previous);
      }
    }

    if (reachable.size > primaryReachSize) {
      primaryReachSize = reachable.size;
      primarySink = sink;
    }
  }

  const forwardReachable = new Set<string>();
  const forwardQueue = [...sources];

  while (forwardQueue.length > 0) {
    const node = forwardQueue.shift()!;
    if (forwardReachable.has(node)) continue;

    forwardReachable.add(node);
    for (const next of adjacency.get(node) || []) {
      forwardQueue.push(next);
    }
  }

  const backwardReachable = new Set<string>();
  const backwardQueue = [primarySink];

  while (backwardQueue.length > 0) {
    const node = backwardQueue.shift()!;
    if (backwardReachable.has(node)) continue;

    backwardReachable.add(node);
    for (const previous of reverseAdj.get(node) || []) {
      backwardQueue.push(previous);
    }
  }

  let voidCount = 0;
  for (const id of nodeIds) {
    if (forwardReachable.has(id) && !backwardReachable.has(id)) {
      voidCount++;
    }
  }

  return voidCount;
}

