import type { FoldStrategy } from '../types.js';

/**
 * Consensus: interference-based fold.
 * - Constructive: values that agree with majority survive
 * - Destructive: outliers are filtered out
 */
export function consensus<T>(
  mode: 'constructive' | 'destructive',
  compare: (a: T, b: T) => boolean,
): FoldStrategy<T, T> {
  return { type: 'consensus', mode, compare };
}
