import type { Stream, StreamId } from './types.js';

/**
 * Entanglement: shared state across parallel streams (confluence).
 * Entangled streams share a mutable state reference. When one stream
 * updates the shared state, all entangled streams see the change.
 *
 * This is NOT synchronization — it's shared memory. Streams are responsible
 * for their own coordination semantics.
 */
export interface EntangledGroup<T, S = unknown> {
  streamIds: StreamId[];
  sharedState: S;
}

/**
 * Entangle a set of streams around a shared state.
 * Marks each stream as 'entangled' and records peer references.
 */
export function entangle<T, S>(
  streams: Stream<T>[],
  sharedState: S,
): EntangledGroup<T, S> {
  const ids = streams.map((s) => s.id);

  for (const stream of streams) {
    if (stream.state === 'pending') {
      stream.state = 'superposed';
    }
    stream.entangledWith = ids.filter((id) => id !== stream.id);
  }

  return { streamIds: ids, sharedState };
}

/**
 * Create work functions that receive a shared state reference.
 * The shared state is passed to each work function, enabling coordination.
 */
export function entangledWork<T, S>(
  sharedState: S,
  workFns: ((shared: S) => Promise<T>)[],
): (() => Promise<T>)[] {
  return workFns.map((fn) => () => fn(sharedState));
}
