import type { Stream, StreamId, PipelineConfig } from './types.js';
import { ReynoldsTracker } from './reynolds.js';

/**
 * Turbulent multiplexer: fills idle pipeline slots with background work.
 *
 * When the pipeline Reynolds number drops (idle capacity), the multiplexer
 * invokes the onIdleSlot callback to get background work to fill the gap.
 * When main pipeline work needs a slot, background work is preempted.
 */
export class TurbulentMultiplexer {
  private reynolds: ReynoldsTracker;
  private onIdleSlot?: PipelineConfig['onIdleSlot'];
  private backgroundStreams = new Set<StreamId>();
  private checkInterval: ReturnType<typeof setInterval> | null = null;

  constructor(reynolds: ReynoldsTracker, onIdleSlot?: PipelineConfig['onIdleSlot']) {
    this.reynolds = reynolds;
    this.onIdleSlot = onIdleSlot;
  }

  /**
   * Start monitoring for idle slots.
   */
  start(intervalMs: number = 100): void {
    if (!this.onIdleSlot || this.checkInterval) return;

    this.checkInterval = setInterval(() => {
      this.fillIdleSlots();
    }, intervalMs);
  }

  /**
   * Stop monitoring.
   */
  stop(): void {
    if (this.checkInterval) {
      clearInterval(this.checkInterval);
      this.checkInterval = null;
    }
  }

  /**
   * Check for idle slots and fill them with background work.
   */
  fillIdleSlots(): Stream[] {
    if (!this.onIdleSlot) return [];

    const idle = this.reynolds.idleSlots;
    if (idle <= 0) return [];

    const newStreams = this.onIdleSlot(idle);
    if (!newStreams || newStreams.length === 0) return [];

    for (const stream of newStreams) {
      this.backgroundStreams.add(stream.id);
      this.reynolds.updateStream(stream.id, 'active');
    }

    return newStreams;
  }

  /**
   * Preempt background streams to make room for primary work.
   * Returns the number of slots freed.
   */
  preempt(count: number): number {
    let freed = 0;
    for (const id of this.backgroundStreams) {
      if (freed >= count) break;
      this.backgroundStreams.delete(id);
      this.reynolds.removeStream(id);
      freed++;
    }
    return freed;
  }

  get backgroundCount(): number {
    return this.backgroundStreams.size;
  }

  isBackground(streamId: StreamId): boolean {
    return this.backgroundStreams.has(streamId);
  }
}
