import type { FoldStrategy, StreamId } from '../types.js';

/**
 * Weighted: pheromone-trail merge.
 * Each stream's result is paired with its weight for the merger.
 */
export function weighted<T, R>(
  weights: Map<StreamId, number>,
  merge: (weighted: [T, number][]) => R,
): FoldStrategy<T, R> {
  return { type: 'weighted', weights, merge };
}
