import type { SearchConfig } from './types.js';

export interface SearchResult<T> {
  best: T;
  iterations: number;
  evaluations: number;
}

/**
 * Grover-style amplification loop.
 *
 * Each iteration:
 * 1. Superpose: evaluate all candidates via oracle
 * 2. Interfere: identify best performers (amplify) and worst (suppress)
 * 3. Mutate: generate next generation from survivors
 * 4. Converge: check if spread is below threshold
 *
 * Unlike classical search, this amplifies the probability of finding good solutions
 * by concentrating resources on the most promising candidates each generation.
 */
export async function search<T>(
  initialCandidates: T[],
  config: SearchConfig<T>,
): Promise<SearchResult<T>> {
  const {
    width,
    oracle,
    mutate,
    convergenceThreshold = 0.001,
    maxIterations = 100,
    strategy = 'amplify-mutate',
  } = config;

  let candidates = initialCandidates.slice(0, width);
  let iterations = 0;
  let evaluations = 0;
  let bestCandidate = candidates[0];
  let bestScore = -Infinity;

  // Pre-allocate scored array — reused every iteration
  const scored: { candidate: T; score: number }[] = new Array(width);
  for (let i = 0; i < width; i++) scored[i] = { candidate: candidates[0], score: 0 };

  while (iterations < maxIterations) {
    // 1. Evaluate all candidates — reuse scored array
    const len = candidates.length;
    for (let i = 0; i < len; i++) {
      evaluations++;
      scored[i].candidate = candidates[i];
      scored[i].score = oracle(candidates[i]);
    }

    // Insertion sort for small arrays (N ≤ ~30 beats Array.sort)
    // Sort only the active portion in-place
    for (let i = 1; i < len; i++) {
      const key = scored[i];
      const keyScore = key.score;
      let j = i - 1;
      while (j >= 0 && scored[j].score < keyScore) {
        scored[j + 1] = scored[j];
        j--;
      }
      scored[j + 1] = key;
    }

    // Track global best
    if (scored[0].score > bestScore) {
      bestScore = scored[0].score;
      bestCandidate = scored[0].candidate;
    }

    // 2. Check convergence — min/max without spreading (avoids call stack limits)
    let minScore = scored[0].score;
    let maxScore = scored[0].score;
    for (let i = 1; i < len; i++) {
      const s = scored[i].score;
      if (s < minScore) minScore = s;
      if (s > maxScore) maxScore = s;
    }
    const spread = maxScore - minScore;

    if (spread <= convergenceThreshold) {
      break;
    }

    // 3. Select survivors and generate next generation
    iterations++;

    if (strategy === 'amplify-mutate') {
      // Top half survives, mutated to fill remaining slots
      const halfWidth = Math.ceil(width / 2);
      const next: T[] = [];

      for (let i = 0; i < halfWidth && next.length < width; i++) {
        next.push(scored[i].candidate);
        if (next.length < width) {
          next.push(mutate(scored[i].candidate, iterations));
        }
      }

      candidates = next.length > width ? next.slice(0, width) : next;
    } else if (strategy === 'oracle-guided') {
      // All candidates mutated, weighted by score
      candidates = new Array(len);
      for (let i = 0; i < len; i++) {
        candidates[i] = mutate(scored[i].candidate, iterations);
      }
    } else {
      // Filter: only keep those above median
      const median = scored[Math.floor(len / 2)].score;
      candidates = [];

      for (let i = 0; i < len && candidates.length < width; i++) {
        if (scored[i].score >= median) {
          candidates.push(mutate(scored[i].candidate, iterations));
        }
      }

      // Fill remaining with mutations of best
      while (candidates.length < width) {
        candidates.push(mutate(bestCandidate, iterations));
      }
    }
  }

  return { best: bestCandidate, iterations, evaluations };
}
